unsafe_example:
// UNSAFE: user-controlled redirect target
app.get('/login/callback', (req, res) => {
  const returnUrl = req.query.returnTo;
  res.redirect(returnUrl); // attacker sets returnTo=https://evil.com
});

safe_example:
// SAFE: validate redirect target against allowlist
const ALLOWED_PATHS = ['/dashboard', '/settings', '/profile'];

app.get('/login/callback', (req, res) => {
  const returnTo = req.query.returnTo || '/dashboard';
  // Only allow relative paths that are in the allowlist
  if (ALLOWED_PATHS.includes(returnTo)) {
    res.redirect(returnTo);
  } else {
    res.redirect('/dashboard');
  }
});
